#!/bin/bash
# =============================================================
# SCRIPT DE SETUP - Ejecuta esto en Google Cloud Shell
# Copia todo este bloque y pégalo en la terminal de Cloud Shell
# =============================================================

echo "🚀 Configurando proyecto Chatbot Maxim Domenech..."

# 1. Crear carpeta
mkdir -p ~/maxim-chatbot && cd ~/maxim-chatbot

# 2. Crear archivos desde datos comprimidos
echo '' | base64 -d | tar xzf -

echo "✅ Archivos creados:"
ls -la ~/maxim-chatbot/

# 3. Habilitar APIs necesarias
echo ""
echo "🔧 Habilitando Cloud Run y Cloud Build..."
gcloud services enable run.googleapis.com cloudbuild.googleapis.com secretmanager.googleapis.com

echo ""
echo "✅ ¡Todo listo! Ahora necesitas:"
echo "   1. Crear el secreto con tu API key de Anthropic:"
echo '      echo -n "TU-API-KEY" | gcloud secrets create anthropic-api-key --data-file=-'
echo ""
echo "   2. Desplegar:"
echo "      cd ~/maxim-chatbot && gcloud run deploy maxim-chatbot --source . --region us-central1 --allow-unauthenticated --set-secrets=ANTHROPIC_API_KEY=anthropic-api-key:latest --memory 256Mi --min-instances 0 --max-instances 2"
